PRAGMA foreign_keys = OFF;
BEGIN IMMEDIATE;
CREATE TABLE request_receipts (operation_id TEXT PRIMARY KEY,request_id TEXT NOT NULL,actor_id TEXT NOT NULL CHECK (actor_id = 'owner'),device_id TEXT NOT NULL,credential_id TEXT NOT NULL,transport TEXT NOT NULL CHECK (transport IN ('cookie','bearer')),host_instance_id TEXT NOT NULL,executor TEXT NOT NULL CHECK (executor IN ('http','assistant','agent-work')),operation TEXT NOT NULL CHECK (operation IN ('capture','settle','resolve','agent-work-complete','agent-work-drain','apply-proposal','reject-proposal','create-document','edit-document')),operation_class TEXT NOT NULL CHECK (operation_class IN ('operational-transaction','workspace-mutation')),state TEXT NOT NULL CHECK (state IN ('admitted','succeeded','rejected','failed','cancelled','interrupted')),result_code TEXT,commit_oid TEXT CHECK (commit_oid IS NULL OR (length(commit_oid) = 40 AND commit_oid NOT GLOB '*[^0-9a-f]*')),adoption_state TEXT NOT NULL CHECK (adoption_state IN ('none','pending','unknown')),recovery_required INTEGER NOT NULL CHECK (recovery_required IN (0,1)),admitted_at TEXT NOT NULL,finished_at TEXT,CHECK ((state = 'admitted' AND result_code IS NULL AND finished_at IS NULL AND recovery_required = 0) OR (state <> 'admitted' AND result_code IS NOT NULL AND finished_at IS NOT NULL)),CHECK (state <> 'interrupted' OR recovery_required = 1),CHECK ((state = 'admitted' AND commit_oid IS NULL AND adoption_state = 'none') OR (state = 'interrupted' AND commit_oid IS NULL AND adoption_state = 'unknown') OR (state NOT IN ('admitted','interrupted') AND ((commit_oid IS NULL AND adoption_state = 'none') OR (commit_oid IS NOT NULL AND adoption_state = 'pending')))));
CREATE TABLE request_receipts_meta (schema_hash TEXT NOT NULL PRIMARY KEY,built_at TEXT NOT NULL);
INSERT INTO "request_receipts" ("operation_id", "request_id", "actor_id", "device_id", "credential_id", "transport", "host_instance_id", "executor", "operation", "operation_class", "state", "result_code", "commit_oid", "adoption_state", "recovery_required", "admitted_at", "finished_at") VALUES ('receipt-admitted', 'request-a', 'owner', 'device-active', 'credential-active', 'cookie', 'host-old', 'http', 'capture', 'workspace-mutation', 'admitted', NULL, NULL, 'none', 0, '2026-07-13T12:12:00.000Z', NULL);
INSERT INTO "request_receipts" ("operation_id", "request_id", "actor_id", "device_id", "credential_id", "transport", "host_instance_id", "executor", "operation", "operation_class", "state", "result_code", "commit_oid", "adoption_state", "recovery_required", "admitted_at", "finished_at") VALUES ('receipt-interrupted', 'request-c', 'owner', 'device-active', 'credential-active', 'bearer', 'host-old', 'assistant', 'edit-document', 'workspace-mutation', 'interrupted', 'host-restarted', NULL, 'unknown', 1, '2026-07-13T12:14:00.000Z', '2026-07-13T12:14:01.000Z');
INSERT INTO "request_receipts" ("operation_id", "request_id", "actor_id", "device_id", "credential_id", "transport", "host_instance_id", "executor", "operation", "operation_class", "state", "result_code", "commit_oid", "adoption_state", "recovery_required", "admitted_at", "finished_at") VALUES ('receipt-succeeded', 'request-b', 'owner', 'device-active', 'credential-active', 'cookie', 'host-old', 'http', 'capture', 'workspace-mutation', 'succeeded', 'captured', '7777777777777777777777777777777777777777', 'pending', 0, '2026-07-13T12:13:00.000Z', '2026-07-13T12:13:01.000Z');
INSERT INTO "request_receipts_meta" ("schema_hash", "built_at") VALUES ('286a2bebc2214df1c383b952dcc2b3f12699a5874c169952c16a074c56c55a9d', '2026-07-13T12:00:00.000Z');
CREATE INDEX request_receipts_by_device ON request_receipts(device_id, admitted_at DESC);
CREATE INDEX request_receipts_by_request ON request_receipts(request_id, admitted_at DESC);
CREATE INDEX request_receipts_by_state ON request_receipts(state, admitted_at);
COMMIT;
